const root = $input.first().json;
const b = root.body || root;
const params = {};
if (b.clientName) params.clientName = String(b.clientName);
if (b.phoneLast10) params.phoneLast10 = String(b.phoneLast10);
if (b.groupName) params.groupName = String(b.groupName);
const hasSeed = params.clientName || params.phoneLast10 || params.groupName;
if (!hasSeed) return [{ json: { __bad: true } }];
// toPhone/caption go TOP-LEVEL (same shape the gateway sends) so the access guard sees them
// Pass the caller's secret through params so the report guard can recognise the admin panel.
if (b.internalSecret) params.internalSecret = String(b.internalSecret);
const out = { operation: 'generate_report', params: JSON.stringify(params) };
if (b.toPhone) out.toPhone = String(b.toPhone);
if (b.caption) out.caption = String(b.caption);
return [{ json: out }];
